sql:
SELECT AVG(value) AS average_experiment_value
FROM experiments
WHERE created_by = 1;

SELECT MAX(value) AS mean_reciprocal_rank
FROM performance_metrics
WHERE name = 'mean_reciprocal_rank';

external_knowledge:
; Last access date refers to the most recent date when an experiment was accessed; 
; Average value and version count are calculated across different versions of an experiment; 
; Document count and total document size are calculated for all documents associated with an experiment.

sql:
SELECT AVG(total_duration) AS avg_access_duration
FROM (
    SELECT experiment_id, SUM(duration) AS total_duration
    FROM experiment_access
    GROUP BY experiment_id
) AS experiment_total_durations;
